scwin.sbm_retrieve_submitdone = function (e) {
    var rowCnt = ds_master.getRowCount();
    spa_cnt.setValue(rowCnt);

    if(rowCnt == 0){
        $c.win.alert(E_MSG_CM_ERR_003);
    } else {
        gr_master.setFocusedCell(0,0);
    }
};


scwin.btn_init_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_retrieveButton_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.btn_save_onclick = function (e) {
    scwin.f_adapt();
};

scwin.btn_close_onclick = function (e) {
    $c.win.closePopup();
};

//-------------------------------------------------------------------------
// 대문자 입력
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

scwin.excelDown = async function () {

    const options = {
        fileName : "Booking별 컨테이너 내역.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName : "Booking별 컨테이너 내역",
        startRowIndex : 0,
        startColumnIndex : 0,
    };

    // 타이틀
    const infoArr = [];

    var chk = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");

    if(chk){
        $c.data.downloadGridViewExcel(gr_master, options, infoArr);
    }

}
